<script lang="ts">let{data,form}=$props();</script><svelte:head><title>文章分类｜暮色工作台</title></svelte:head><header class="studio-head"><div><p class="eyebrow">POST CATEGORIES</p><h1>文章分类</h1><p>分类会显示在博客侧栏、文章卡片和正文页。</p></div><a class="primary" href="/studio/posts">返回写作</a></header>{#if form?.message}<div class:success={form.success} class="notice">{form.message}</div>{/if}<div class="manager-grid"><section class="studio-panel manage-list">{#each data.categories as category}<article><i class="color-dot" style={`background:${category.color}`}></i><div><b>{category.name}</b><small>{category.postCount} 篇文章 · 排序 {category.sortOrder}</small><span>{category.description}</span></div><form method="POST" action="?/delete" onsubmit={(e)=>!confirm('只有没有文章的分类才能删除，继续？')&&e.preventDefault()}><input type="hidden" name="id" value={category.id}/><button class="danger">删除</button></form></article>{/each}</section><section class="studio-panel editor"><p class="eyebrow">NEW CATEGORY</p><h2>新建文章分类</h2><form method="POST" action="?/save" class="studio-form"><label>分类名称<input name="name" required /></label><label>分类网址标识 <small>用于筛选链接，留空自动生成</small><input name="slug" placeholder="例如：build-log" /></label><label>分类说明<textarea name="description" rows="4"></textarea></label><div class="two"><label>识别色<input name="color" type="color" value="#6857d9" /></label><label>排序<input name="sortOrder" type="number" value="100" /></label></div><button class="primary">保存文章分类</button></form></section></div>
